function ControlledDialog() {
  const [open, setOpen] = React.useState(false);
  const [content, setContent] = React.useState('');

  const handleOpenDialog = (type) => {
    setContent(`This is a ${type} message.`);
    setOpen(true);
  };

  return (
    <>
      <button onClick={() => handleOpenDialog('success')}>Open Success Dialog</button>
      <button onClick={() => handleOpenDialog('error')}>Open Error Dialog</button>

      <Dialog.Root open={open} onOpenChange={setOpen}>
        <Dialog.Portal>
          <Dialog.Overlay />
          <Dialog.Content>
            <Dialog.Title>Dynamic Content</Dialog.Title>
            <Dialog.Description>{content}</Dialog.Description>
            <Dialog.Close asChild>
              <button>Close</button>
            </Dialog.Close>
          </Dialog.Content>
        </Dialog.Portal>
      </Dialog.Root>
    </>
  );
}
// In your app: <ControlledDialog />
